class Solution {
    public int countLargestGroup(int n) {
        int[] count = new int[37]; // max sum of digits for 4-digit number is 9+9+9+9 = 36
        int maxCount = 0, res = 0;
        for (int i = 1; i <= n; i++) {
            int sum = 0, num = i;
            while (num > 0) {
                sum += num % 10;
                num /= 10;
            }
            count[sum]++;
            if (count[sum] > maxCount) {
                maxCount = count[sum];
                res = 1;
            } else if (count[sum] == maxCount) {
                res++;
            }
        }
        return res;
    }
}
```
